18	/**
19	 * API for constructing SQL string (especially the whitespace part).
20	 *
21	 * It hides the internal implementation.
22	 * Originally it used plain string concatenation, which was expensive.
23	 * Now it's storing items to array and builds the string only in the end.
24	 */
25	export default class Layout {
26	  private items: LayoutItem[] = [];
27	
28	  constructor(public indentation: Indentation) {}
29	
30	  /**
31	   * Appends token strings and whitespace modifications to SQL string.
32	   */
33	  public add(...items: (WS | string)[]) {
34	    for (const item of items) {
35	      switch (item) {
36	        case WS.SPACE:
37	          this.items.push(WS.SPACE);
38	          break;
39	        case WS.NO_SPACE:
40	          this.trimHorizontalWhitespace();
41	          break;
42	        case WS.NO_NEWLINE:
43	          this.trimWhitespace();
44	          break;
45	        case WS.NEWLINE:
46	          this.trimHorizontalWhitespace();
47	          this.addNewline(WS.NEWLINE);
48	          break;
49	        case WS.MANDATORY_NEWLINE:
50	          this.trimHorizontalWhitespace();
51	          this.addNewline(WS.MANDATORY_NEWLINE);
52	          break;
53	        case WS.INDENT:
54	          this.addIndentation();
55	          break;
56	        case WS.SINGLE_INDENT:
57	          this.items.push(WS.SINGLE_INDENT);
58	          break;
59	        default:
