  describe('BigQuery pipe syntax', () => {
    it('formats a chain of pipe operators', () => {
      const result = format(
        'FROM table |> WHERE x > 1 |> SELECT x, y |> ORDER BY x |> LIMIT 10;'
      );
      expect(result).toBe(dedent`
        FROM
          table
        |> WHERE
          x > 1
        |> SELECT
          x,
          y
        |> ORDER BY
          x
        |> LIMIT 10;
      `);
    });

    it('formats AGGREGATE pipe operator with nested GROUP BY', () => {
      const result = format('FROM table |> AGGREGATE COUNT(*) AS cnt GROUP BY x;');
      expect(result).toBe(dedent`
        FROM
          table
        |> AGGREGATE
          COUNT(*) AS cnt
          GROUP BY
            x;
      `);
    });

    it('formats AGGREGATE pipe operator without GROUP BY', () => {
      const result = format('FROM table |> AGGREGATE COUNT(*) AS cnt;');
      expect(result).toBe(dedent`
        FROM
          table
        |> AGGREGATE
          COUNT(*) AS cnt;
      `);
    });

    it('formats EXTEND, SET and DROP pipe operators', () => {
      const result = format('FROM table |> EXTEND x + 1 AS y |> SET z = 3 |> DROP a, b;');
      expect(result).toBe(dedent`
        FROM
          table
        |> EXTEND
          x + 1 AS y
        |> SET
          z = 3
        |> DROP
          a,
          b;
      `);
    });

    it('formats JOIN pipe operator on a single line', () => {
      const result = format('FROM t1 |> JOIN t2 ON t1.id = t2.id;');
      expect(result).toBe(dedent`
        FROM
          t1
        |> JOIN t2 ON t1.id = t2.id;
      `);
    });

    it('formats AS pipe operator on a single line', () => {
      const result = format('FROM t1 |> AS aliased;');
      expect(result).toBe(dedent`
        FROM
          t1
        |> AS aliased;
      `);
    });

    it('formats LIMIT pipe operator with OFFSET on a single line', () => {
      const result = format('FROM table |> LIMIT 10 OFFSET 5;');
      expect(result).toBe(dedent`
        FROM
          table
        |> LIMIT 10 OFFSET 5;
      `);
    });

    it('allows AGGREGATE and EXTEND to be used as plain identifiers elsewhere', () => {
      const result = format('SELECT aggregate, extend FROM tbl;');
      expect(result).toBe(dedent`
        SELECT
          aggregate,
          extend
        FROM
          tbl;
      `);
    });

    it('formats pipe queries nested as a subquery', () => {
      const result = format('SELECT * FROM (FROM t |> WHERE x > 1 |> SELECT x) sub;');
      expect(result).toBe(dedent`
        SELECT
          *
        FROM
          (
            FROM
              t
            |> WHERE
              x > 1
            |> SELECT
              x
          ) sub;
      `);
    });

    it('formats keywordCase for pipe-exclusive keywords', () => {
      const result = format('FROM table |> aggregate COUNT(*) AS cnt |> extend x + 1 AS y;', {
        keywordCase: 'lower',
      });
      expect(result).toBe(dedent`
        from
          table
        |> aggregate
          COUNT(*) as cnt
        |> extend
          x + 1 as y;
      `);
    });
  });
